import sys
import random
from collections import deque

class Solution:
    def recoverMaxHeap(self, nums: list[int]) -> bool:
        if len(nums) < 2:
            return True

        queue = deque()

        for i in range(1, len(nums), 2):
            left = nums[i - 1]
            right = nums[i]

            if left < right:
                queue.append((left, right))

        while queue:
            parent, child = queue.popleft()

            if child < parent:
                return False

            if child * 2 + 1 < len(nums):
                queue.append((child, nums[child * 2 + 1]))

        return True


